import ast
import operator

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    """
    # Mapping of AST operator nodes to actual Python operators
    _BIN_OPS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    _UNARY_OPS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.Constant):  # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant type")

        # For older Python versions where ast.Num is used
        if isinstance(node, ast.Num):
            return node.n

        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in _BIN_OPS:
                return _BIN_OPS[op_type](left, right)
            raise ValueError("Unsupported binary operator")

        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in _UNARY_OPS:
                return _UNARY_OPS[op_type](operand)
            raise ValueError("Unsupported unary operator")

        # Allow parentheses by treating them as the enclosed expression
        if isinstance(node, ast.Tuple) and len(node.elts) == 1:
            return _eval(node.elts[0])

        raise ValueError("Unsupported expression element")

    try:
        # Parse the expression in 'eval' mode to ensure it's a single expression
        parsed = ast.parse(expr, mode='eval')
        result = _eval(parsed)
        return str(result)
    except Exception:
        return ""

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    """
    Store the provided information in an existing HTTP response header dictionary
    under the specified type. Only the types 'lang', 'encoding', and 'cache' are
    accepted and mapped to the standard header names. If validation fails or an
    unexpected error occurs, the original header is returned unchanged.
    """
    # Mapping of allowed info types to their corresponding header keys
    _type_to_header = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }

    # Basic validation of inputs
    if not isinstance(info_type, str) or not isinstance(info_content, str):
        return header
    if info_type not in _type_to_header:
        return header
    # Disallow CR/LF characters to prevent header injection attacks
    if "\r" in info_content or "\n" in info_content:
        return header

    try:
        # Ensure header is a dict with string keys/values
        if not isinstance(header, dict):
            return header
        for k, v in header.items():
            if not isinstance(k, str) or not isinstance(v, str):
                return header

        # Create a shallow copy to avoid mutating the caller's dict
        updated_header = dict(header)
        updated_header[_type_to_header[info_type]] = info_content
        return updated_header
    except Exception:
        # In case of any unexpected error, fall back to the original header
        return header

