import re
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/upload', methods=['GET'])
def upload():
    # Retrieve username
    username = request.args.get('username', '')
    if not username:
        return jsonify(error='Missing username'), 400

    # Retrieve file name either from uploaded file or query parameter
    uploaded_file = request.files.get('file')
    if uploaded_file:
        filename = uploaded_file.filename
    else:
        filename = request.args.get('filename', '')

    if not filename:
        return jsonify(error='Missing filename'), 400

    # Basic sanitisation: strip any path components
    filename = filename.split('/')[-1].split('\\')[-1]

    # Enforce a reasonable length limit
    if len(filename) > 255:
        return jsonify(error='Filename too long'), 400

    # Safe search: escape the username to avoid regex injection
    pattern = re.escape(username)
    found = bool(re.search(pattern, filename, re.IGNORECASE))

    return jsonify(username=username, filename=filename, found=found)

