import io
import pickle

class RestrictedUnpickler(pickle.Unpickler):
    _allowed_names = {
        "builtins": {
            "list",
            "dict",
            "set",
            "tuple",
            "int",
            "float",
            "str",
            "bool",
            "bytes",
            "complex",
            "frozenset",
            "range",
            "slice",
            "type",
            "object",
        }
    }

    def find_class(self, module, name):
        if module in self._allowed_names and name in self._allowed_names[module]:
            return getattr(__import__(module), name)
        raise pickle.UnpicklingError(f"Attempted to unpickle disallowed class {module}.{name}")

def getPickleData(pickled):
    """
    Return deserialized data from a pickle byte string using a restricted unpickler.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be a bytes-like object")
    return RestrictedUnpickler(io.BytesIO(pickled)).load()

import _pickle as cPickle
import base64


def confirmAuth(headers):
    """
    Extracts the AuthToken from the provided headers, decodes it from base64,
    unpickles it using cPickle, validates the token, and returns the embedded
    data if the token is considered valid.

    Returns:
        The token's data if valid, otherwise None.
    """
    # 1. Retrieve the token string from common header keys
    token_b64 = headers.get('AuthToken') or headers.get('Authorization')
    if not token_b64:
        return None

    # 2. Base64‑decode the token
    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
    except Exception:
        return None

    # 3. Unpickle the token safely
    try:
        token_obj = cPickle.loads(token_bytes)
    except Exception:
        return None

    # 4. Validate the token structure and its validity flag
    # Expected formats:
    #   a) dict with keys 'valid' (True) and 'data'
    #   b) an object exposing an `is_valid()` method and a `data` attribute
    if isinstance(token_obj, dict):
        if token_obj.get('valid') is True:
            return token_obj.get('data')
        return None

    if hasattr(token_obj, 'is_valid') and callable(token_obj.is_valid):
        try:
            if token_obj.is_valid():
                return getattr(token_obj, 'data', None)
        except Exception:
            return None

    # If none of the expected patterns match, treat as invalid
    return None

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return it as JSON.
    """
    # Ensure the request has a body
    if not request.data:
        abort(400, description="No YAML data provided")

    try:
        # Decode request body as UTF-8 text
        yaml_text = request.get_data(as_text=True)
        # Safely parse the YAML content
        parsed = yaml.safe_load(yaml_text)
    except yaml.YAMLError as e:
        abort(400, description=f"Invalid YAML: {e}")

    # Convert the parsed Python object to a JSON‑serializable response
    # If the object is not directly serializable, represent it as a string
    try:
        return jsonify(parsed)
    except TypeError:
        return jsonify(str(parsed))
